$code = '[DllImport("ntdll.dll")] public static extern int NtQueryTimerResolution(out uint min, out uint max, out uint cur);'; $type = Add-Type -MemberDefinition $code -Name 'Win32' -Namespace 'Timer' -PassThru; $min=$max=$cur=0; $type::NtQueryTimerResolution([ref]$min, [ref]$max, [ref]$cur); Write-Host "Dabartinis tikslumas: $($cur/10000) ms" -ForegroundColor Green; Write-Host "Maksimalus galimas: $($max/10000) ms" -ForegroundColor Cyan
